import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { PORTFOLIO_TEMPLATES } from '../data/staticData';
import { CheckCircle, Plus, ArrowRight, Monitor } from 'lucide-react';
import './PortfolioTemplatesPage.css';

const TemplatePreviewMini = ({ tpl }) => {
  const { style, primaryColor, accentColor, bgColor } = tpl;

  if (style === 'terminal') return (
    <div className="ptpl-mini" style={{ background: bgColor }}>
