      <div className="ptpl-content" style={{ padding: 10 }}>
        <div className="ptpl-line w60" style={{ background: primaryColor, height: 8 }} />
        <div className="ptpl-line w40" style={{ background: accentColor, height: 5 }} />
        <div className="ptpl-skills-row">
          {[40,50,35,55].map((w,i) => <div key={i} className="ptpl-tag" style={{ width: w, background: `${primaryColor}30`, borderColor: `${primaryColor}60` }} />)}
        </div>
        <div className="ptpl-line w85" style={{ background: 'rgba(255,255,255,0.1)', height: 5 }} />
