        <div className="ptpl-line w50" style={{ background: primaryColor, height: 8, marginBottom: 5 }} />
        <div className="ptpl-line w35" style={{ background: accentColor, height: 5 }} />
        <div className="ptpl-chips-wrap">
          {[38,48,30].map((w,i) => <div key={i} style={{ width: w, height: 14, borderRadius: 7, background: 'rgba(255,255,255,0.12)' }} />)}
        </div>
      </div>
    </div>
  );

  if (style === 'minimal') return (
    <div className="ptpl-mini" style={{ background: bgColor }}>
      <div style={{ padding: 12 }}>
        <div className="ptpl-line w65" style={{ background: '#0F172A', height: 9, marginBottom: 6 }} />
        <div className="ptpl-line w45" style={{ background: primaryColor, height: 5 }} />
        <div style={{ height: 1, background: '#E2E8F0', margin: '10px 0' }} />
        <div className="ptpl-line w80" style={{ background: '#E2E8F0', height: 5 }} />
        <div className="ptpl-line w70" style={{ background: '#E2E8F0', height: 5 }} />
        <div className="ptpl-skills-row">
          {[40,50,35].map((w,i) => <div key={i} style={{ width: w, height: 18, borderRadius: 20, background: `${primaryColor}15`, border: `1px solid ${primaryColor}30` }} />)}
        </div>
      </div>
    </div>
  );

  if (style === 'neon') return (
    <div className="ptpl-mini" style={{ background: bgColor }}>
      <div style={{ padding: 10 }}>
        <div style={{ height: 2, background: primaryColor, boxShadow: `0 0 8px ${primaryColor}`, marginBottom: 10, borderRadius: 1 }} />
        <div className="ptpl-line w55" style={{ background: primaryColor, height: 8, boxShadow: `0 0 6px ${primaryColor}60` }} />
