  if (style === 'corporate') return (
    <div className="ptpl-mini" style={{ background: bgColor, display: 'flex' }}>
      <div style={{ width: 28, background: primaryColor, flexShrink: 0 }}>
        {[0,1,2,3,4].map(i => <div key={i} style={{ height: 6, background: 'rgba(255,255,255,0.3)', margin: '8px 4px', borderRadius: 2 }} />)}
      </div>
      <div style={{ flex: 1, padding: 10 }}>
        <div className="ptpl-line w60" style={{ background: '#1E293B', height: 8 }} />
        <div className="ptpl-line w40" style={{ background: primaryColor, height: 5 }} />
        <div className="ptpl-line w80" style={{ background: '#E2E8F0', height: 5 }} />
        <div className="ptpl-line w70" style={{ background: '#E2E8F0', height: 5 }} />
