};

const PortfolioTemplatesPage = () => {
  const navigate = useNavigate();
  const { selectedPortfolioTemplate, setSelectedPortfolioTemplate, setPortfolioStyle } = useApp();

  const handleSelect = (tpl) => {
    setSelectedPortfolioTemplate(tpl.id);
    if (!tpl.isCustom) {
      setPortfolioStyle(prev => ({
        ...prev,
        primaryColor: tpl.primaryColor,
        accentColor: tpl.accentColor,
        bgColor: tpl.bgColor,
        textColor: tpl.textColor,
        layout: tpl.layout,
      }));
    }
  };

  const handleContinue = () => {
    if (selectedPortfolioTemplate) navigate('/portfolio/customize');
  };

  return (
    <div className="ptpl-page">
      <div className="container">
        <div className="ptpl-header">
          <p className="section-eyebrow"><Monitor size={13} /> Portfolio Builder — Step 1 of 3</p>
          <h1 className="ptpl-title">Choose Your Portfolio Template</h1>
          <p className="ptpl-subtitle">
            Select a tech-themed template as your starting point, or create your own from scratch.
            You'll customize everything in the next step.
          </p>
        </div>

        <div className="ptpl-grid">
          {PORTFOLIO_TEMPLATES.map(tpl => {
            const isSelected = selectedPortfolioTemplate === tpl.id;
            return (
              <div
                key={tpl.id}
                className={`ptpl-card ${isSelected ? 'selected' : ''} ${tpl.isCustom ? 'custom-card' : ''}`}
                onClick={() => handleSelect(tpl)}
              >
                {isSelected && (
                  <div className="ptpl-selected-badge">
                    <CheckCircle size={14} /> Selected
                  </div>
                )}
                <div className="ptpl-preview">
                  <TemplatePreviewMini tpl={tpl} />
                </div>
                <div className="ptpl-info">
                  <div className="ptpl-name-row">
                    <h3 className="ptpl-name">{tpl.name}</h3>
                    <div className="ptpl-color-dot" style={{ background: tpl.primaryColor }} />
                  </div>
                  <p className="ptpl-desc">{tpl.description}</p>
                  <div className="ptpl-tags">
                    {tpl.tags.map(t => (
                      <span key={t} className={`ptpl-tag-badge ${t === 'Custom' ? 'tag-custom' : 'tag-std'}`}>{t}</span>
                    ))}
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="ptpl-footer">
          {selectedPortfolioTemplate && (
            <div className="ptpl-selected-info animate-fadeIn">
              <CheckCircle size={17} color="var(--success)" />
              <span>
                <strong>{PORTFOLIO_TEMPLATES.find(t => t.id === selectedPortfolioTemplate)?.name}</strong> selected
              </span>
            </div>
          )}
          <button className="btn-primary ptpl-continue-btn" onClick={handleContinue} disabled={!selectedPortfolioTemplate}>
            Customize Portfolio <ArrowRight size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default PortfolioTemplatesPage;
